// CalculateInterest calculates the compound interest based on the given parameters.
// Parameters:
// - principal: The initial amount of money.
// - rate: The annual interest rate (in decimal, e.g., 0.05 for 5%).
// - time: The time period in years.
// - frequency: The number of times interest is applied per year.
// Returns:
// - The calculated compound interest as a float64.
// Errors:
// - Returns an error if any input value is invalid.
func CalculateInterest(principal float64, rate float64, time float64, frequency int) (float64, error) {
	if principal <= 0 {
		return 0, errors.New("principal must be greater than zero")
	}
	if rate <= 0 || rate >= 1 {
		return 0, errors.New("rate must be between 0 and 1 (exclusive)")
	}
	if time <= 0 {
		return 0, errors.New("time must be greater than zero")
	}
	if frequency <= 0 {
		return 0, errors.New("frequency must be greater than zero")
	}

	compoundInterest := principal * math.Pow(1+(rate/float64(frequency)), float64(frequency)*time)
	return compoundInterest, nil
}

func main() {
	// Example usage
	principal := 1000.0
	rate := 0.05
	time := 5.0
	frequency := 4

	result, err := CalculateInterest(principal, rate, time, frequency)
	if err != nil {
		fmt.Println("Error:", err)
	} else {
		fmt.Printf("Compound Interest: %.2f\n", result)
	}
}

