/**
 * Evaluates a reverse Polish notation (RPN) expression.
 * 
 * @param expression The RPN expression as a string, with operands and operators separated by spaces.
 * @return The computed result as an integer.
 * @throws IllegalArgumentException if the expression is malformed or division by zero is attempted.
 */
public int evaluateRPNExpression(String expression) {
    Stack<Integer> stack = new Stack<>(); // Note: Stack to hold operands
    String[] tokens = expression.split(" "); // Note: Split expression into tokens

    for (String token : tokens) {
        switch (token) {
            case "+":
                if (stack.size() < 2) throw new IllegalArgumentException("Malformed expression");
                stack.push(stack.pop() + stack.pop()); // Note: Perform addition
                break;
            case "-":
                if (stack.size() < 2) throw new IllegalArgumentException("Malformed expression");
                int b = stack.pop();
                int a = stack.pop();
                stack.push(a - b); // Note: Perform subtraction
                break;
            case "*":
                if (stack.size() < 2) throw new IllegalArgumentException("Malformed expression");
                stack.push(stack.pop() * stack.pop()); // Note: Perform multiplication
                break;
            case "/":
                if (stack.size() < 2) throw new IllegalArgumentException("Malformed expression");
                int divisor = stack.pop();
                int dividend = stack.pop();
                if (divisor == 0) throw new IllegalArgumentException("Division by zero");
                stack.push(dividend / divisor); // Note: Perform division
                break;
            default:
                try {
                    stack.push(Integer.parseInt(token)); // Note: Push operand to stack
                } catch (NumberFormatException e) {
                    throw new IllegalArgumentException("Malformed expression");
                }
                break;
        }
    }

    if (stack.size() != 1) throw new IllegalArgumentException("Malformed expression"); // Note: Ensure there's only one result
    return stack.pop(); // Note: Return the final result
}
